1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
14	
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	
19	type Scenario = {
20	  customer: { yearsWithMHPCO: number };
21	  steps: Array<{ op: "quote"; items: Item[] }>;
22	};
23	
24	type QuoteResult = { premium: number };
25	
26	const COMPONENT_BLOCK_SIZE = 3;
27	const COMPONENT_BLOCK_PREMIUM = 60;
28	
29	const formsComponentBlock = (items: Item[]): boolean =>
30	  items.length === COMPONENT_BLOCK_SIZE && items.every((item) => item.type === items[0].type);
31	
32	const sumOfBasePremiums = (items: Item[]): number =>
33	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
34	
35	const groupByType = (items: Item[]): Item[][] => {
36	  const groups = items.reduce<Record<string, Item[]>>((acc, item) => {
37	    (acc[item.type] ??= []).push(item);
38	    return acc;
39	  }, {});
40	  return Object.values(groups);
41	};
42	
43	const basePremiumForGroup = (group: Item[]): number =>
44	  formsComponentBlock(group) ? COMPONENT_BLOCK_PREMIUM : sumOfBasePremiums(group);
45	
46	const basePremiumFor = (items: Item[]): number =>
47	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
48	
49	type SurchargeRule = { rate: number; applies: (item: Item) => boolean };
50	
51	const SURCHARGE_RULES: SurchargeRule[] = [
52	  { rate: CURSE_SURCHARGE_RATE, applies: (item) => !!item.cursed },
53	  {
54	    rate: HIGH_ENCHANTMENT_SURCHARGE_RATE,
55	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
56	  },
57	];
58	
59	const surchargeForRule = (items: Item[], rule: SurchargeRule): number =>
60	  items.reduce(
61	    (sum, item) => (rule.applies(item) ? sum + BASE_PREMIUMS[item.type] * rule.rate : sum),
62	    0,
63	  );
64	
65	const surchargesFor = (items: Item[]): number =>
66	  SURCHARGE_RULES.reduce((total, rule) => total + surchargeForRule(items, rule), 0);
67	
68	const quotePremium = (items: Item[]): QuoteResult => {
69	  const base = basePremiumFor(items);
70	  const surcharges = surchargesFor(items);
71	  return {
72	    premium: Math.ceil(base + surcharges + base * FIRST_INSURANCE_RATE + PROCESSING_FEE),
73	  };
74	};
75	
76	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
77	  const results = scenario.steps.map((step) => quotePremium(step.items));
78	  return { results };
79	};
